import Navbar from "./Navbar";
import Title from './Title'
import theme from '../theme'
import { useState, useEffect } from 'react'

const Layout = ({ children }) => {

  return (
    <>
      <style>{style}</style>
      <iframe style={{width:'100vh', height:'90vh'}} src="https://editor.p5js.org/jithunni.ks/embed/Q19ApoNm4"></iframe>
      <div className='overall-wrapper'>
        <div className='wrapper'>
          <Title />
          <Navbar />
          {children}
        </div>
      </div>
    </>
  )
};

const style = `
  * {
    font-family:Roboto;
  }
  ol {
      padding-left:1rem;
  }
  .overall-wrapper {
    position: fixed;
    top:0;
    width: 100%;
    height: 100%;
    overflow
  }
  .wrapper {
    width:70vw;
    margin:auto;
    min-width:600px;
  }
  body {
    background-color:${theme.darkBackground};
  }
  iframe {
    margin:0;
    padding:0;
    border:none;
  }
`;

export default Layout;
